import { renderToStaticMarkup } from 'react-dom/server'
function InfoIcon() { return <span>i</span>; }
function WarningIcon() { return <span>!</span>; }
const components = { info: InfoIcon, warning: WarningIcon };
function Notice({ type }) {
  const SelectedIcon = components[type];
  return <SelectedIcon />;
}
console.log(renderToStaticMarkup(<Notice type="warning" />));

